import React, { useEffect, useMemo, useState } from 'react';
import { AlertTriangle, ClipboardCheck, Globe, Truck } from 'lucide-react';
import SiteNavbar from '../components/layout/SiteNavbar';
import SiteFooter from '../components/layout/SiteFooter';
import RegisterParcel from '../components/register/RegisterParcel';
import ParcelsTable from '../components/list/ParcelsTable';
import TrackParcel from '../components/track/TrackParcel';
import {
  createParcel,
  fetchAdminParcels,
  fetchAdminStats,
  mapServerParcel,
  trackParcel,
  updateParcelStatus,
} from '../services/api';

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [parcels, setParcels] = useState([]);
  const [loadingParcels, setLoadingParcels] = useState(true);
  const [registerLoading, setRegisterLoading] = useState(false);
  const [statusLoading, setStatusLoading] = useState(false);
  const [trackState, setTrackState] = useState({ result: null, error: null, loading: false });

  const refreshData = async () => {
    setLoadingParcels(true);
    try {
      const [statsData, parcelData] = await Promise.all([fetchAdminStats(), fetchAdminParcels()]);
      setStats(statsData.totals);
      setParcels(parcelData.map(mapServerParcel));
    } catch (error) {
      console.error(error);
    } finally {
      setLoadingParcels(false);
    }
  };

  useEffect(() => {
    refreshData();
  }, []);

  const handleRegisterParcel = async (form, reset) => {
    setRegisterLoading(true);
    try {
      const parcel = await createParcel(form);
      alert(`Parcel registered! Tracking ID: ${parcel.trackingId}`);
      reset();
      refreshData();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to register parcel');
    } finally {
      setRegisterLoading(false);
    }
  };

  const handleStatusChange = async (parcelId, status) => {
    setStatusLoading(true);
    try {
      const parcel = await updateParcelStatus(parcelId, status);
      setParcels((prev) => prev.map((p) => (p.id === parcel._id || p.id === parcelId ? mapServerParcel(parcel) : p)));
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to update status');
    } finally {
      setStatusLoading(false);
    }
  };

  const handleTrackParcel = async (trackingId) => {
    setTrackState({ result: null, error: null, loading: true });
    try {
      const parcel = await trackParcel(trackingId);
      setTrackState({ result: parcel, error: null, loading: false });
    } catch (error) {
      setTrackState({ result: null, error: error.response?.data?.message || 'Not found', loading: false });
    }
  };

  const statCards = useMemo(
    () => [
      { label: 'Total Shipments', value: stats?.total ?? 0, icon: Globe, color: 'primary' },
      { label: 'Pending', value: stats?.pending ?? 0, icon: AlertTriangle, color: 'warning' },
      { label: 'In Transit', value: stats?.transit ?? 0, icon: Truck, color: 'info' },
      { label: 'Delivered (24h)', value: stats?.delivered ?? 0, icon: ClipboardCheck, color: 'success' },
    ],
    [stats]
  );

  return (
    <div className="d-flex flex-column min-vh-100">
      <SiteNavbar />
      <main className="container py-4 flex-grow-1">
        <div className="mb-4">
          <h1 className="fw-bold">Admin Control Centre</h1>
          <p className="text-muted">Monitor nationwide parcels, update statuses, and onboard new bookings.</p>
        </div>

        <section className="row g-3 mb-4">
          {statCards.map((card) => (
            <div className="col-md-3" key={card.label}>
              <div className={`card border-0 shadow-sm text-${card.color}`}>
                <div className="card-body">
                  <card.icon size={28} className="mb-2" />
                  <div className="fw-bold fs-4 text-dark">{card.value}</div>
                  <div className="text-muted small">{card.label}</div>
                </div>
              </div>
            </div>
          ))}
        </section>

        <div className="row g-4 mb-4">
          <div className="col-lg-6">
            <RegisterParcel onSubmit={handleRegisterParcel} isLoading={registerLoading} title="Book on behalf of customer" />
          </div>
          <div className="col-lg-6">
            <div className="card border-0 shadow-sm h-100">
              <div className="card-body">
                <TrackParcel
                  onTrack={handleTrackParcel}
                  result={trackState.result}
                  error={trackState.error}
                  isLoading={trackState.loading}
                />
              </div>
            </div>
          </div>
        </div>

        {loadingParcels ? (
          <p className="text-muted">Loading parcels...</p>
        ) : (
          <ParcelsTable
            parcels={parcels}
            onStatusChange={handleStatusChange}
            isUpdating={statusLoading}
            mode="admin"
          />
        )}
      </main>
      <SiteFooter />
    </div>
  );
}
